Event Start
&GAMRepository = GAMrepository.Get() If &GAMRepository.AuthenticationMasterRepositoryId.IsEmpty() //User Authentication Type &AuthenticationTypeName.Clear() &AuthenticationTypes = GAMRepository.GetEnabledAuthenticationTypes(&Language, &Errors) For &AuthenticationTypesIns in &AuthenticationTypes &AuthenticationTypeName.AddItem(&AuthenticationTypesIns.Name, &AuthenticationTypesIns.Description) EndFor Else &AuthenticationTypeName.Visible = False Endif
//User Security Policy &SecurityPolicies = GAMRepository.GetSecurityPolicies(&FilterSecPol, &Errors) &SecurityPolicyId.AddItem(0,"(None)") For &SecurityPolicy in &SecurityPolicies &SecurityPolicyId.AddItem(&SecurityPolicy.Id,&SecurityPolicy.Name) EndFor If &Mode = GAMAPiMode.Insert &IsEnabledInRepository.Enabled = False &AuthenticationTypeName.Enabled = True &AuthenticationTypeName = !"local" &AuthTypeId = &AuthenticationType.GetTypeByName(&AuthenticationTypeName, &Errors) &Repository = GAMRepository.Get() &UserNameSpace = &Repository.NameSpace &EnableTwoFactorAuthentication = False
Else // Mode = Update &User.Load(&UserId) &AuthenticationTypeName.Enabled = False &AuthenticationTypeName = &User.AuthenticationTypeName &AuthTypeId = &AuthenticationType.GetTypeByName(&AuthenticationTypeName, &Errors) If &AuthTypeId = GAMAuthenticationTypes.GAMLocal &Name.Enabled = True &Image.Enabled = True &URLProfile.Enabled = False Else &Name.Enabled = False &Image.Enabled = False &URLProfile.Enabled = True Endif &UserId = &User.GUID &UserNameSpace = &User.NameSpace &Name = &User.Name &EMail = &User.EMail &FirstName = &User.FirstName &LastName = &User.LastName If not &User.URLImage.IsEmpty() &Image.FromURL(&User.URLImage) Endif //&Photo.FromURL(&User.GetPhoto(&Errors)) &ExternalId = &User.ExternalId &Birthday = &User.Birthday &Gender = GAMUserGender.Convert(&User.Gender) &Phone = &User.Phone &IsActive = &User.IsActive
&ActivationDate = &User.ActivationDate &DontReceiveInformation = &User.DontReceiveInformation &CannotChangePassword = &User.CannotChangePassword &MustChangePassword = &User.MustChangePassword &PasswordNeverExpires = &User.PasswordNeverExpires &IsBlocked = &User.IsBlocked &SecurityPolicyId = &User.SecurityPolicyId &IsEnabledInRepository = &User.IsEnabledInRepository &DateLastAuthentication = &User.DateLastAuthentication &EnableTwoFactorAuthentication = &User.EnableTwoFactorAuthentication &OTPDailyNumberCodes = &User.OTPDailyNumberCodes &OTPLastDateRequestCode = &User.OTPLastDateRequestCode &OTPLastLockedDate = &User.OTPLastLockedDate &OTPNumberLocked = &User.OTPNumberLocked
Endif
If &Mode = GAMAPiMode.Display or &Mode = GAMAPiMode.Delete &Name.Enabled = False &EMail.Enabled = False &FirstName.Enabled = False &LastName.Enabled = False &URLProfile.Enabled = False &ExternalId.Enabled = False &Birthday.Enabled = False &Gender.Enabled = False &Phone.Enabled = False &IsActive.Enabled = False &DontReceiveInformation.Enabled = False &CannotChangePassword.Enabled = False &MustChangePassword.Enabled = False &IsBlocked.Enabled = False &PasswordNeverExpires.Enabled = False &SecurityPolicyId.Enabled = False &IsEnabledInRepository.Enabled = False If &EnableTwoFactorAuthentication &EnableTwoFactorAuthentication.Enabled = False &OTPDailyNumberCodes.Enabled = False &OTPLastDateRequestCode.Enabled = False &OTPLastLockedDate.Enabled = False &OTPNumberLocked.Enabled = False Endif If &Mode = GAMAPiMode.Delete BtnEnter.Caption = "WWP_GAM_Delete" Else BtnEnter.Visible = False EndIf
Endif If &IsActive &IsActive.Enabled = False Endif
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Do 'AttributesSecurityCode' User_IsEnabledInRepository.Visible = False
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event Refresh
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Do 'CheckSecurityForActions'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event 'DoSendActivationEmail'
&User.Load(&UserId) If not &User.IsActive &UserActivationKey = &User.GetNewActivationKey(&Errors) Commit &LinkURL = GAMRepository.ApplicationGetAccountActivationURL("") GAMCheckUserActivationMethod(&UserId, &LinkURL, &Messages) For &Message in &Messages Msg(&Message.Description) EndFor Endif
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event 'DoUrlProfileGo'
Link(&URLProfile)
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Sub 'CheckSecurityForActions'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not (not &IsActive AND &GAMRepository.Email.SendEmailWhenUserActivateAccount) BtnSendActivationEmail.Visible = False Endif If not (&Mode <> GAMAPiMode.Insert And (not &User.URLProfile.IsEmpty() AND &User.AuthenticationTypeName <> GAMAuthenticationTypes.GAMLocal)) BtnUrlProfileGo.Visible = False Endif
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CheckRequiredFields'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&CheckRequiredFieldsResult = True If &Name.IsEmpty() Msg(DVMessageGetBasicNotificationMsg('', Format('WWP_RequiredAttribute','WWP_GAM_UserName'), DVMessageType.error, &Name.InternalName, DVMessageBoolean.True, '')) &CheckRequiredFieldsResult = False EndIf If (&GAMRepository.RequiredEmail) AND &Email.IsEmpty() Msg(DVMessageGetBasicNotificationMsg('', Format('WWP_RequiredAttribute','WWP_GAM_Email'), DVMessageType.error, &Email.InternalName, DVMessageBoolean.True, '')) &CheckRequiredFieldsResult = False EndIf If (&GAMRepository.RequiredPassword And &AuthTypeId = GAMAuthenticationTypes.GAMLocal) AND &Password.IsEmpty() Msg(DVMessageGetBasicNotificationMsg('', Format('WWP_RequiredAttribute','WWP_GAM_Password'), DVMessageType.error, &Password.InternalName, DVMessageBoolean.True, '')) &CheckRequiredFieldsResult = False EndIf If (&GAMRepository.RequiredPassword And &AuthTypeId = GAMAuthenticationTypes.GAMLocal) AND &PasswordConf.IsEmpty() Msg(DVMessageGetBasicNotificationMsg('', Format('WWP_RequiredAttribute','WWP_GAM_ConfPassword'), DVMessageType.error, &PasswordConf.InternalName, DVMessageBoolean.True, '')) &CheckRequiredFieldsResult = False EndIf If (&GAMRepository.RequiredFirstName) AND &FirstName.IsEmpty() Msg(DVMessageGetBasicNotificationMsg('', Format('WWP_RequiredAttribute','WWP_GAM_FirstName'), DVMessageType.error, &FirstName.InternalName, DVMessageBoolean.True, '')) &CheckRequiredFieldsResult = False EndIf If (&GAMRepository.RequiredLastName) AND &LastName.IsEmpty() Msg(DVMessageGetBasicNotificationMsg('', Format('WWP_RequiredAttribute','WWP_GAM_LastName'), DVMessageType.error, &LastName.InternalName, DVMessageBoolean.True, '')) &CheckRequiredFieldsResult = False EndIf If (&GAMRepository.RequiredBirthday) AND &Birthday.IsEmpty() Msg(DVMessageGetBasicNotificationMsg('', Format('WWP_RequiredAttribute','WWP_GAM_Birthday'), DVMessageType.error, &Birthday.InternalName, DVMessageBoolean.True, '')) &CheckRequiredFieldsResult = False EndIf If (&GAMRepository.RequiredGender) AND &Gender.IsEmpty() Msg(DVMessageGetBasicNotificationMsg('', Format('WWP_RequiredAttribute','WWP_GAM_Gender'), DVMessageType.error, &Gender.InternalName, DVMessageBoolean.True, '')) &CheckRequiredFieldsResult = False EndIf If (&GAMRepository.RequiredPhone) AND &Phone.IsEmpty() Msg(DVMessageGetBasicNotificationMsg('', Format('WWP_RequiredAttribute','WWP_GAM_Phone'), DVMessageType.error, &Phone.InternalName, DVMessageBoolean.True, '')) &CheckRequiredFieldsResult = False EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AttributesSecurityCode'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If Not (&AuthenticationTypeName.Count > 1) &AuthenticationTypeName.Visible = False AuthenticationTypeName_Cell.Class = !'Invisible' Else &AuthenticationTypeName.Visible = True AuthenticationTypeName_Cell.Class = !'col-xs-12 col-sm-6 DataContentCell' EndIf If &GAMRepository.RequiredEmail Email_Cell.Class = !'col-xs-12 col-sm-6 RequiredDataContentCell' Else Email_Cell.Class = !'col-xs-12 col-sm-6 DataContentCell' EndIf If Not (&AuthTypeId = GAMAuthenticationTypes.GAMLocal and &Mode = GAMAPiMode.Insert) &Password.Visible = False Password_Cell.Class = !'Invisible' Else &Password.Visible = True If &GAMRepository.RequiredPassword And &AuthTypeId = GAMAuthenticationTypes.GAMLocal Password_Cell.Class = !'col-xs-12 col-sm-6 RequiredDataContentCell' Else Password_Cell.Class = !'col-xs-12 col-sm-6 DataContentCell' EndIf EndIf If Not (&AuthTypeId = GAMAuthenticationTypes.GAMLocal and &Mode = GAMAPiMode.Insert) &PasswordConf.Visible = False PasswordConf_Cell.Class = !'Invisible' Else &PasswordConf.Visible = True If &GAMRepository.RequiredPassword And &AuthTypeId = GAMAuthenticationTypes.GAMLocal PasswordConf_Cell.Class = !'col-xs-12 col-sm-6 RequiredDataContentCell' Else PasswordConf_Cell.Class = !'col-xs-12 col-sm-6 DataContentCell' EndIf EndIf If &GAMRepository.RequiredFirstName FirstName_Cell.Class = !'col-xs-12 col-sm-6 RequiredDataContentCell' Else FirstName_Cell.Class = !'col-xs-12 col-sm-6 DataContentCell' EndIf If &GAMRepository.RequiredLastName LastName_Cell.Class = !'col-xs-12 col-sm-6 RequiredDataContentCell' Else LastName_Cell.Class = !'col-xs-12 col-sm-6 DataContentCell' EndIf If &GAMRepository.RequiredBirthday Birthday_Cell.Class = !'col-xs-12 col-sm-6 RequiredDataContentCell' Else Birthday_Cell.Class = !'col-xs-12 col-sm-6 DataContentCell' EndIf If &GAMRepository.RequiredGender Gender_Cell.Class = !'col-xs-12 col-sm-6 RequiredDataContentCell' Else Gender_Cell.Class = !'col-xs-12 col-sm-6 DataContentCell' EndIf If &GAMRepository.RequiredPhone Phone_Cell.Class = !'col-xs-12 col-sm-6 RequiredDataContentCell' Else Phone_Cell.Class = !'col-xs-12 col-sm-6 DataContentCell' EndIf If Not (&Mode <> GAMAPiMode.Insert And not &User.URLImage.IsEmpty()) &Image.Visible = False Image_Cell.Class = !'Invisible' Else &Image.Visible = True Image_Cell.Class = !'col-xs-12 col-sm-6 DataContentCell' EndIf If Not (&Mode <> GAMAPiMode.Insert) &IsActive.Visible = False IsActive_Cell.Class = !'Invisible' Else &IsActive.Visible = True IsActive_Cell.Class = !'col-xs-12 col-sm-6 DataContentCell' EndIf If Not (&Mode <> GAMAPiMode.Insert) &IsEnabledInRepository.Visible = False IsEnabledInRepository_Cell.Class = !'Invisible' Else &IsEnabledInRepository.Visible = True IsEnabledInRepository_Cell.Class = !'col-xs-12 col-sm-6 DataContentCell' EndIf If Not (&Mode <> GAMAPiMode.Insert) &DateLastAuthentication.Visible = False DateLastAuthentication_Cell.Class = !'Invisible' Else &DateLastAuthentication.Visible = True DateLastAuthentication_Cell.Class = !'col-xs-12 col-sm-6 DataContentCell' EndIf If Not (&GAMRepository.IsTwoFactorAuthenticationEnabled()) &EnableTwoFactorAuthentication.Visible = False EnableTwoFactorAuthentication_Cell.Class = !'Invisible' Else &EnableTwoFactorAuthentication.Visible = True EnableTwoFactorAuthentication_Cell.Class = !'col-xs-12 col-sm-6 DataContentCell' EndIf If Not (&GAMRepository.IsOneTimePasswordEnabled()) &OTPNumberLocked.Visible = False OTPNumberLocked_Cell.Class = !'Invisible' Else &OTPNumberLocked.Visible = True OTPNumberLocked_Cell.Class = !'col-xs-12 col-sm-6 DataContentCell' EndIf If Not (&GAMRepository.IsOneTimePasswordEnabled()) &OTPLastLockedDate.Visible = False OTPLastLockedDate_Cell.Class = !'Invisible' Else &OTPLastLockedDate.Visible = True OTPLastLockedDate_Cell.Class = !'col-xs-12 col-sm-6 DataContentCell' EndIf If Not (&GAMRepository.IsOneTimePasswordEnabled()) &OTPDailyNumberCodes.Visible = False OTPDailyNumberCodes_Cell.Class = !'Invisible' Else &OTPDailyNumberCodes.Visible = True OTPDailyNumberCodes_Cell.Class = !'col-xs-12 col-sm-6 DataContentCell' EndIf If Not (&GAMRepository.IsOneTimePasswordEnabled()) &OTPLastDateRequestCode.Visible = False OTPLastDateRequestCode_Cell.Class = !'Invisible' Else &OTPLastDateRequestCode.Visible = True OTPLastDateRequestCode_Cell.Class = !'col-xs-12 col-sm-6 DataContentCell' EndIf If Not (&Mode <> GAMAPiMode.Insert) &ActivationDate.Visible = False ActivationDate_Cell.Class = !'Invisible' Else &ActivationDate.Visible = True ActivationDate_Cell.Class = !'DataContentCell' EndIf If Not (&Mode <> GAMAPiMode.Insert And &AuthTypeId <> GAMAuthenticationTypes.GAMLocal) &URLProfile.Visible = False URLProfile_Cell.Class = !'Invisible' Else &URLProfile.Visible = True URLProfile_Cell.Class = !'DataContentCell' EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Event Enter
Do 'CheckRequiredFields' If &CheckRequiredFieldsResult If &Mode <> TrnMode.Insert &User.Load(&UserId) Endif &PasswordIsOK = True Do Case Case &Mode = GAMAPiMode.Insert or &Mode = GAMAPiMode.Update If &Mode = GAMAPiMode.Insert &AuthTypeId = &AuthenticationType.GetTypeByName(&AuthenticationTypeName, &Errors) &IsEnabledInRepository = true If &AuthTypeId = GAMAuthenticationTypes.GAMLocal If &Password <> &PasswordConf &PasswordIsOK = False Msg("WWP_GAM_PasswordNotMatch") Endif Else &Password = NullValue(&Password) Endif Endif If &PasswordIsOK &User.AuthenticationTypeName = &AuthenticationTypeName &User.Name = &Name &User.EMail = &EMail &User.FirstName = &FirstName &User.LastName = &LastName &User.Password = &Password &User.ExternalId = &ExternalId &User.Birthday = &Birthday &User.Phone = &Phone &User.Gender.FromString(&Gender) &User.IsActive = &IsActive &BlobPhoto = &Photo //&User.SetPhoto(&BlobPhoto, &Errors) &User.URLProfile = &URLProfile &User.DontReceiveInformation= &DontReceiveInformation &User.CannotChangePassword = &CannotChangePassword &User.MustChangePassword = &MustChangePassword &User.IsBlocked = &IsBlocked &User.PasswordNeverExpires = &PasswordNeverExpires &User.SecurityPolicyId = &SecurityPolicyId &User.EnableTwoFactorAuthentication = &EnableTwoFactorAuthentication &User.Save() Endif Case &Mode = GAMAPiMode.Delete &User.Delete() EndCase If &PasswordIsOK If &User.Success()
Commit &isOK = True If &Mode <> GAMAPiMode.Insert If &IsEnabledInRepository <> &User.IsEnabledInRepository If &IsEnabledInRepository &isOK = &User.RepositoryEnable(&Errors) Else &isOK = &User.RepositoryDisable(&Errors) EndIf EndIf EndIf If &isOK commit If &Mode = GAMAPiMode.Delete GAMWWUsers() Else Return EndIf Else For &Error in &Errors Msg(Format(!"%1 (GAM%2)", &Error.Message, &Error.Code)) EndFor EndIf Else &Errors = &User.GetErrors() For &Error in &Errors Msg(Format(!"%1 (GAM%2)", &Error.Message, &Error.Code)) EndFor Endif Endif Endif
EndEvent
Event &AuthenticationTypeName.IsValid
&AuthTypeId = &AuthenticationType.GetTypeByName(&AuthenticationTypeName, &Errors) Do 'AttributesSecurityCode'
EndEvent
